{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOrzRnxXc8siJz2G6zR3Mgd"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"wAoHkookVTTv","executionInfo":{"status":"ok","timestamp":1773122475281,"user_tz":-180,"elapsed":105,"user":{"displayName":"Bassem Amin","userId":"03844483762484690298"}}},"outputs":[],"source":["\"\"\"\n","subscription.py\n","----------------\n","Defines the SubscriptionPlan and Subscription classes for managing\n","StreamFlix user subscriptions.\n","\n","Author: [Your Name]\n","Date: [Submission Date]\n","\"\"\"\n","\n","from datetime import date, timedelta\n","\n","\n","class SubscriptionPlan:\n","    \"\"\"\n","    Represents a subscription tier offered by StreamFlix.\n","\n","    Attributes:\n","        __plan_id (int): Unique plan identifier.\n","        __plan_name (str): Name of the plan (e.g., 'Basic', 'Standard', 'Premium').\n","        __price (float): Monthly price in USD.\n","        __access_level (int): Numeric level (1=Basic, 2=Standard, 3=Premium).\n","        __duration_days (int): Validity period in days.\n","        __features (list[str]): List of features included in the plan.\n","    \"\"\"\n","\n","    _id_counter = 3000\n","\n","    def __init__(self, plan_name: str, price: float, access_level: int,\n","                 duration_days: int = 30, features: list = None):\n","        \"\"\"\n","        Initialise a new SubscriptionPlan.\n","\n","        Args:\n","            plan_name (str): Name of the plan.\n","            price (float): Monthly price (must be >= 0).\n","            access_level (int): Access level (1, 2, or 3).\n","            duration_days (int): Validity in days. Default 30.\n","            features (list[str]): List of feature descriptions. Default empty.\n","\n","        Raises:\n","            ValueError: If price < 0 or access_level not in {1, 2, 3}.\n","        \"\"\"\n","        if price < 0:\n","            raise ValueError(\"Price cannot be negative.\")\n","        if access_level not in (1, 2, 3):\n","            raise ValueError(\"Access level must be 1 (Basic), 2 (Standard), or 3 (Premium).\")\n","\n","        SubscriptionPlan._id_counter += 1\n","        self.__plan_id = SubscriptionPlan._id_counter\n","        self.__plan_name = plan_name\n","        self.__price = price\n","        self.__access_level = access_level\n","        self.__duration_days = duration_days\n","        self.__features = features if features else []\n","\n","    # ── Getters ──────────────────────────────────────────────\n","    def get_plan_id(self) -> int:\n","        \"\"\"Return the plan ID.\"\"\"\n","        return self.__plan_id\n","\n","    def get_plan_name(self) -> str:\n","        \"\"\"Return the plan name.\"\"\"\n","        return self.__plan_name\n","\n","    def get_price(self) -> float:\n","        \"\"\"Return the monthly price.\"\"\"\n","        return self.__price\n","\n","    def get_access_level(self) -> int:\n","        \"\"\"Return the access level.\"\"\"\n","        return self.__access_level\n","\n","    def get_duration_days(self) -> int:\n","        \"\"\"Return the duration in days.\"\"\"\n","        return self.__duration_days\n","\n","    def get_features(self) -> list:\n","        \"\"\"Return the list of features.\"\"\"\n","        return list(self.__features)\n","\n","    def get_plan_details(self) -> dict:\n","        \"\"\"\n","        Return all plan details as a dictionary.\n","\n","        Returns:\n","            dict: Plan attributes.\n","        \"\"\"\n","        return {\n","            'plan_id': self.__plan_id,\n","            'plan_name': self.__plan_name,\n","            'price': self.__price,\n","            'access_level': self.__access_level,\n","            'duration_days': self.__duration_days,\n","            'features': self.__features\n","        }\n","\n","    def update_price(self, new_price: float) -> None:\n","        \"\"\"\n","        Update the plan price.\n","\n","        Args:\n","            new_price (float): New price (must be >= 0).\n","\n","        Raises:\n","            ValueError: If price is negative.\n","        \"\"\"\n","        if new_price < 0:\n","            raise ValueError(\"Price cannot be negative.\")\n","        self.__price = new_price\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a user-friendly string.\"\"\"\n","        return (f\"Plan[{self.__plan_id}] {self.__plan_name} - \"\n","                f\"${self.__price:.2f}/month | Level: {self.__access_level} | \"\n","                f\"Duration: {self.__duration_days} days\")\n","\n","\n","class Subscription:\n","    \"\"\"\n","    Represents an active subscription linking a User to a SubscriptionPlan.\n","    Uses aggregation for the plan (plan exists independently).\n","\n","    Attributes:\n","        __subscription_id (int): Unique subscription identifier.\n","        __user (User): The subscribed user.\n","        __plan (SubscriptionPlan): The selected plan.\n","        __start_date (date): When the subscription started.\n","        __end_date (date): When the subscription expires.\n","        __status (str): Current status ('Active', 'Cancelled', 'Expired').\n","    \"\"\"\n","\n","    _id_counter = 4000\n","\n","    def __init__(self, user, plan: SubscriptionPlan):\n","        \"\"\"\n","        Create a new Subscription.\n","\n","        Args:\n","            user (User): The subscribing user.\n","            plan (SubscriptionPlan): The chosen plan.\n","        \"\"\"\n","        Subscription._id_counter += 1\n","        self.__subscription_id = Subscription._id_counter\n","        self.__user = user\n","        self.__plan = plan\n","        self.__start_date = date.today()\n","        self.__end_date = self.__start_date + timedelta(days=plan.get_duration_days())\n","        self.__status = \"Active\"\n","        # Update user subscription status\n","        user.set_subscription_status(\"Active\")\n","\n","    # ── Getters ──────────────────────────────────────────────\n","    def get_subscription_id(self) -> int:\n","        \"\"\"Return the subscription ID.\"\"\"\n","        return self.__subscription_id\n","\n","    def get_user(self):\n","        \"\"\"Return the subscribed user.\"\"\"\n","        return self.__user\n","\n","    def get_plan(self) -> SubscriptionPlan:\n","        \"\"\"Return the subscription plan.\"\"\"\n","        return self.__plan\n","\n","    def get_start_date(self) -> date:\n","        \"\"\"Return the start date.\"\"\"\n","        return self.__start_date\n","\n","    def get_end_date(self) -> date:\n","        \"\"\"Return the end date.\"\"\"\n","        return self.__end_date\n","\n","    def get_status(self) -> str:\n","        \"\"\"Return the subscription status.\"\"\"\n","        return self.__status\n","\n","    # ── Actions ──────────────────────────────────────────────\n","    def activate(self) -> None:\n","        \"\"\"Activate the subscription.\"\"\"\n","        self.__status = \"Active\"\n","        self.__user.set_subscription_status(\"Active\")\n","        print(f\"Subscription {self.__subscription_id} activated for {self.__user.get_name()}.\")\n","\n","    def cancel(self) -> None:\n","        \"\"\"Cancel the subscription.\"\"\"\n","        self.__status = \"Cancelled\"\n","        self.__user.set_subscription_status(\"Cancelled\")\n","        print(f\"Subscription {self.__subscription_id} cancelled for {self.__user.get_name()}.\")\n","\n","    def upgrade(self, new_plan: SubscriptionPlan) -> None:\n","        \"\"\"\n","        Upgrade to a higher-tier plan.\n","\n","        Args:\n","            new_plan (SubscriptionPlan): The new plan (must have higher access level).\n","\n","        Raises:\n","            ValueError: If new plan is not a higher level.\n","        \"\"\"\n","        if new_plan.get_access_level() <= self.__plan.get_access_level():\n","            raise ValueError(\"New plan must have a higher access level to upgrade.\")\n","        old_plan_name = self.__plan.get_plan_name()\n","        self.__plan = new_plan\n","        self.__end_date = date.today() + timedelta(days=new_plan.get_duration_days())\n","        print(f\"Subscription upgraded from {old_plan_name} to {new_plan.get_plan_name()}.\")\n","\n","    def downgrade(self, new_plan: SubscriptionPlan) -> None:\n","        \"\"\"\n","        Downgrade to a lower-tier plan.\n","\n","        Args:\n","            new_plan (SubscriptionPlan): The new plan (must have lower access level).\n","\n","        Raises:\n","            ValueError: If new plan is not a lower level.\n","        \"\"\"\n","        if new_plan.get_access_level() >= self.__plan.get_access_level():\n","            raise ValueError(\"New plan must have a lower access level to downgrade.\")\n","        old_plan_name = self.__plan.get_plan_name()\n","        self.__plan = new_plan\n","        self.__end_date = date.today() + timedelta(days=new_plan.get_duration_days())\n","        print(f\"Subscription downgraded from {old_plan_name} to {new_plan.get_plan_name()}.\")\n","\n","    def is_active(self) -> bool:\n","        \"\"\"\n","        Check if the subscription is currently active and not expired.\n","\n","        Returns:\n","            bool: True if active and within validity period.\n","        \"\"\"\n","        return self.__status == \"Active\" and date.today() <= self.__end_date\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a string representation of the subscription.\"\"\"\n","        return (f\"Subscription[{self.__subscription_id}] User: {self.__user.get_name()} | \"\n","                f\"Plan: {self.__plan.get_plan_name()} | Status: {self.__status} | \"\n","                f\"Valid: {self.__start_date} to {self.__end_date}\")"]}]}